{"code": "import json
from collections import defaultdict, Counter

# Load the detailed BRCA data with histological types
brca_result = locals()['var_functions.execute_python:36']
if isinstance(brca_result, str) and brca_result.endswith('.json'):
    with open(brca_result, 'r') as f:
        brca_data = json.load(f)
else:
    brca_data = brca_result

# Load CDH1 mutation data
mutation_result = locals()['var_functions.query_db:42']
if isinstance(mutation_result, str) and mutation_result.endswith('.json'):
    with open(mutation_result, 'r') as f:
        cdh1_mutations = json.load(f)
else:
    cdh1_mutations = mutation_result

# Create set of CDH1 mutated patients
cdh1_patients = set([m['ParticipantBarcode'] for m in cdh1_mutations if isinstance(m, dict)])

# Build contingency table: histological type vs CDH1 mutation status
hist_type_to_cdh1 = defaultdict(lambda: {'mutated': 0, 'wildtype': 0})

# Get list of BRCA patients with their histological types
brca_patients_info = []
for record in brca_data:
    if isinstance(record, dict) and 'barcode' in record:
        barcode = record['barcode']
        hist_type = record.get('histological_type', 'Unknown')
        brca_patients_info.append({'barcode': barcode, 'hist_type': hist_type})

# If we stored it as a dict with separate fields
if isinstance(brca_data, dict):
    patient_barcodes = brca_data.get('patient_barcodes', [])
    # We need to reconstruct hist type mapping, let's get it from the original query
    clinical_result = locals()['var_functions.query_db:24']
    if isinstance(clinical_result, str) and clinical_result.endswith('.json'):
        with open(clinical_result, 'r') as f:
            clinical_records = json.load(f)
    else:
        clinical_records = clinical_result

    barcode_to_hist_type = {}
    for record in clinical_records:
        if isinstance(record, dict):
            patient_desc = record.get('Patient_description', '')
            hist_type = record.get('histological_type', 'Unknown')
            import re
            match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', patient_desc)
            if match:
                barcode = match.group(0)
                if barcode in patient_barcodes:
                    barcode_to_hist_type[barcode] = hist_type

    brca_patients_info = [{'barcode': bc, 'hist_type': barcode_to_hist_type.get(bc, 'Unknown')} for bc in patient_barcodes]

# Build the contingency table
for patient in brca_patients_info:
    barcode = patient['barcode']
    hist_type = patient['hist_type']

    if barcode in cdh1_patients:
        hist_type_to_cdh1[hist_type]['mutated'] += 1
    else:
        hist_type_to_cdh1[hist_type]['wildtype'] += 1

# Convert to regular dict for JSON serialization
contingency_table = {}
for hist_type, counts in hist_type_to_cdh1.items():
    contingency_table[hist_type] = dict(counts)

print('__RESULT__:')
print(json.dumps(contingency_table, indent=2))"}
